import okhttp3.Interceptor
import okhttp3.OkHttpClient
import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory
import java.util.concurrent.TimeUnit

const val BASE_URL_DEV = "https://api.example.com/dev/users"
const val BASE_URL_STAGING = "https://api.example.com/staging/users"
const val BASE_URL_PROD = "https://api.example.com/prod/users"

fun provideOkHttpClient(token: String): OkHttpClient {
    return OkHttpClient.Builder()
        .connectTimeout(30, TimeUnit.SECONDS)
        .readTimeout(30, TimeUnit.SECONDS)
        .addInterceptor { chain ->
            val originalRequest = chain.request()
            val newRequest = originalRequest.newBuilder()
                .header("Authorization", "Bearer $token")
                .build()
            chain.proceed(newRequest)
        }
        .build()
}

fun provideRetrofit(client: OkHttpClient, baseUrl: String): Retrofit {
    return Retrofit.Builder()
        .baseUrl(baseUrl)
        .client(client)
        .addConverterFactory(GsonConverterFactory.create())
        .build()
}

interface UserService {
    @GET
    suspend fun getUserProfiles(): List<UserProfile>
}

data class UserProfile(val id: Int, val name: String, val email: String)

fun provideUserService(token: String, environment: String): UserService {
    val baseUrl = when (environment) {
        "dev" -> BASE_URL_DEV
        "staging" -> BASE_URL_STAGING
        else -> BASE_URL_PROD
    }
    val client = provideOkHttpClient(token)
    val retrofit = provideRetrofit(client, baseUrl)
    return retrofit.create(UserService::class.java)
}